1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const countLiveNeighbors = (cell: Cell, alive: ReadonlySet<string>): number => {
12	  const [x, y] = cell;
13	  return NEIGHBOR_OFFSETS.filter(([dx, dy]) => alive.has(keyOf([x + dx, y + dy]))).length;
14	};
15	
16	const survives = (liveNeighbors: number): boolean =>
17	  liveNeighbors === 2 || liveNeighbors === 3;
18	
19	const isBorn = (liveNeighbors: number): boolean => liveNeighbors === 3;
20	
21	export function nextGeneration(cells: Cell[]): Cell[] {
22	  const alive = new Set(cells.map(keyOf));
23	  const survivors = cells.filter((cell) => survives(countLiveNeighbors(cell, alive)));
24	
25	  const candidates = new Map<string, Cell>();
26	  for (const [x, y] of cells) {
27	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
28	      const neighbor: Cell = [x + dx, y + dy];
29	      const key = keyOf(neighbor);
30	      if (!alive.has(key)) candidates.set(key, neighbor);
31	    }
32	  }
33	  const births = [...candidates.values()].filter(
34	    (cell) => isBorn(countLiveNeighbors(cell, alive)),
35	  );
36	
37	  return [...survivors, ...births];
38	}
