const survives = (liveNeighbors: number): boolean =>
  liveNeighbors === 2 || liveNeighbors === 3;

const isBorn = (liveNeighbors: number): boolean => liveNeighbors === 3;

export function nextGeneration(cells: Cell[]): Cell[] {
  const alive = new Set(cells.map(keyOf));
  const survivors = cells.filter((cell) => survives(countLiveNeighbors(cell, alive)));

  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const key = keyOf(neighbor);
      if (!alive.has(key)) candidates.set(key, neighbor);
    }
  }
  const births = [...candidates.values()].filter(
    (cell) => isBorn(countLiveNeighbors(cell, alive)),
  );

  return [...survivors, ...births];
}

